      kny_what_p1: '<strong>Choul Chnam Thmey</strong> (\u1786\u17bc\u179b\u1786\u17d2\u1793\u17b6\u17c6\u1790\u17d2\u1798\u17b8)\ub294 "\uc0c8\ud574\ub85c \ub4e4\uc5b4\uac00\ub2e4"\ub97c \uc758\ubbf8\ud558\uba70 \uce84\ubcf4\ub514\uc544\uc758 \uac00\uc7a5 \ud070 \ucd95\uc81c\uc785\ub2c8\ub2e4. <strong>4\uc6d4 13\uc77c\ubd80\ud130 16\uc77c\uae4c\uc9c0</strong> \uc9c4\ud589\ub429\ub2c8\ub2e4.',
      kny_what_p2: '\uc0c1\uc88c\ubd80 \ubd88\uad50 \uc804\ud1b5\uc5d0 \ubfcc\ub9ac\ub97c \ub454 \uc774 \ucd95\uc81c\ub294 \uc601\uc801 \uc0c8\ub85c\uc6c0, \uc5b4\ub978 \uacf5\uacbd, \uac00\uc871 \ubaa8\uc784\uc758 \uc2dc\uac04\uc785\ub2c8\ub2e4.',
