      kny_day2_date: '2\uc77c\ucc28 \u00b7 4\uc6d4 14\uc77c',
      kny_day2_p: '\ub458\uc9f8 \ub0a0\uc740 \uc790\uc120\uacfc \uc5b4\ub978 \uacf5\uacbd\uc5d0 \ud5cc\uc2e0\ub429\ub2c8\ub2e4. \uc0ac\uc6d0\uc5d0 <strong>\ubaa8\ub798 \uc5b8\ub355</strong>(\u1797\u17d2\u1793\u17c6\u1781\u17d2\u179f\u17b6\u1785\u17cb)\uc744 \uc313\uc2b5\ub2c8\ub2e4.',
