      kny_day3_p: '\ub9c8\uc9c0\ub9c9 \ub0a0\uc740 \uac00\uc7a5 \uc2e0\uc131\ud569\ub2c8\ub2e4. \ud5a5\uc218\ub85c <strong>\ubd88\uc0c1</strong>\uc744 \ubaa9\uc695\uc2dc\ud0b5\ub2c8\ub2e4.',
      kny_traditions_h: '<span class="icon" aria-hidden="true">\u2728</span> \uc804\ud1b5\uacfc \uad00\uc2b5',
      kny_trad1_h: '\uc0ac\uc6d0 \ubc29\ubb38', kny_trad1_p: '\uc2e0\ub3c4\ub4e4\uc740 \ud30c\uace0\ub2e4\uc5d0 \uc74c\uc2dd, \uaf43, \ud5a5\uc744 \uac00\uc838\uc635\ub2c8\ub2e4.',
      kny_trad2_h: '\ubb3c \uc758\uc2dd', kny_trad2_p: '\uc874\uacbd\uc758 \ud45c\uc2dc\ub85c \uc5b4\ub978\uc758 \uc190\uc5d0 \ud5a5\uc218\ub97c \ubd93\uc2b5\ub2c8\ub2e4.',
      kny_trad3_h: '\ubaa8\ub798 \uc5b8\ub355 (\u1797\u17d2\u1793\u17c6\u1781\u17d2\u179f\u17b6\u1785\u17cb)', kny_trad3_p: '\uc0ac\uc6d0\uc5d0 \uc791\uc740 \ubaa8\ub798\uc0b0\uc744 \uc313\uc2b5\ub2c8\ub2e4.',
      kny_trad4_h: '\uc804\ud1b5 \ub180\uc774', kny_trad4_p: '<strong>Chol Chhoung</strong>, <strong>Leak Kanseng</strong>, \uc904\ub2e4\ub9ac\uae30\uac00 \ucee4\ubba4\ub2c8\ud2f0\ub97c \ud558\ub098\ub85c \ubaa8\uc74d\ub2c8\ub2e4.',
      kny_trad5_h: '\ud06c\uba54\ub974 \uc74c\uc2dd', kny_trad5_p: '<strong>Num Ansom</strong>, <strong>Kralan</strong>, \ub2e4\uc591\ud55c \uce74\ub808\uac00 \uba70\uce60 \uc804\uc5d0 \uc900\ube44\ub429\ub2c8\ub2e4.',
