      kny_zodiac_h: '<span class="icon" aria-hidden="true">\ud83d\udc34</span> \ud06c\uba54\ub974 \ub744',
      kny_zodiac_p: '\ud06c\uba54\ub974 \ub744\ub294 12\ub144 \ub3d9\ubb3c \uc21c\ud658\uc785\ub2c8\ub2e4. 2026\ub144\uc740 <strong>\ub9d0\uc758 \ud574</strong>(\u1786\u17d2\u1793\u17b6\u17c6\u1798\u1798\u17b8)\ub85c \uc5d0\ub108\uc9c0, \uc790\uc720, \ubaa8\ud5d8\uc744 \uc0c1\uc9d5\ud569\ub2c8\ub2e4.',
      kny_zodiac_fact_label: '2026 \u2014 \ub9d0\uc758 \ud574 \u00b7 \u1786\u17d2\u1793\u17b6\u17c6\u1798\u1798\u17b8',
      kny_zodiac_fact_p: '\ub9d0\uc740 \ud06c\uba54\ub974 \uc810\uc131\uc220\uc5d0\uc11c \uc5d0\ub108\uc9c0, \uc790\uc720, \ubaa8\ud5d8\uc744 \uc0c1\uc9d5\ud569\ub2c8\ub2e4.',
