    nl: {
      kny_hero_subtitle: 'Choul Chnam Thmey 2026',
      kny_what_h: '<span class="icon" aria-hidden="true">\ud83c\udfdb\ufe0f</span> Wat is Choul Chnam Thmey?',
      kny_what_p1: '<strong>Choul Chnam Thmey</strong> (\u1786\u17bc\u179b\u1786\u17d2\u1793\u17b6\u17c6\u1790\u17d2\u1798\u17b8), wat "het nieuwe jaar binnengaan" betekent, is de meest gevierde feestdag van Cambodja. Gevierd van <strong>13 tot 16 april</strong>.',
      kny_what_p2: 'Geworteld in de Theravada-boeddhistische traditie, is het festival een tijd voor spirituele vernieuwing en familiebijeenkomsten.',
      kny_what_p3: 'De viering valt samen met het einde van het droge seizoen. Het deelt culturele banden met <strong>Songkran</strong> in Thailand, <strong>Pi Mai</strong> in Laos en <strong>Thingyan</strong> in Myanmar.',
      kny_days_h: '<span class="icon" aria-hidden="true">\ud83d\udcff</span> De drie dagen',
      kny_days_intro: 'Choul Chnam Thmey ontvouwt zich over drie ceremoni\u00eble dagen.',
      kny_day1_label: 'Maha Sangkran \u2014 \u1798\u17a0\u17b6\u179f\u1784\u17d2\u1780\u17d2\u179a\u17b6\u1793\u17d2\u178f',
      kny_day1_date: 'Dag 1 \u00b7 13 april',
      kny_day1_p: 'De eerste dag markeert de komst van de nieuwe hemelse engel (<strong>Tevoda</strong>). Families maken hun huizen schoon en dragen nieuwe kleding.',
      kny_day2_label: 'Virak Wanabat \u2014 \u179c\u17b7\u179a:\u179c\u17d0\u1793\u1794\u178f',
      kny_day2_date: 'Dag 2 \u00b7 14 april',
      kny_day2_p: 'De tweede dag is gewijd aan liefdadigheid. Families bouwen <strong>zandheuvels</strong> (\u1797\u17d2\u1793\u17c6\u1781\u17d2\u179f\u17b6\u1785\u17cb) bij tempels.',
      kny_day3_label: 'Tngai Leang Sak \u2014 \u1790\u17d2\u1784\u17c3\u179b\u17be\u1784\u179f\u1780',
      kny_day3_date: 'Dag 3 \u00b7 15\u201316 april',
      kny_day3_p: 'De laatste dag is de heiligste. Boeddhisten baden <strong>Boeddhabeelden</strong> met geparfumeerd water.',
      kny_traditions_h: '<span class="icon" aria-hidden="true">\u2728</span> Tradities en gebruiken',
      kny_trad1_h: 'Tempelbezoeken', kny_trad1_p: 'Gelovigen brengen eten, bloemen en wierook naar pagodes.',
      kny_trad2_h: 'Waterceremoni\u00ebn', kny_trad2_p: 'Geparfumeerd water wordt over de handen van ouderen gegoten.',
      kny_trad3_h: 'Zandheuvels (\u1797\u17d2\u1793\u17c6\u1781\u17d2\u179f\u17b6\u1785\u17cb)', kny_trad3_p: 'Kleine zandbergen worden bij tempels gebouwd.',
      kny_trad4_h: 'Traditionele spellen', kny_trad4_p: '<strong>Chol Chhoung</strong>, <strong>Leak Kanseng</strong> en touwtrekken brengen gemeenschappen samen.',
      kny_trad5_h: 'Khmer-keuken', kny_trad5_p: '<strong>Num Ansom</strong>, <strong>Kralan</strong> en diverse curry\'s worden voorbereid.',
      kny_trad6_h: 'Nieuwe kleding en familie', kny_trad6_p: 'Nieuwe kleding dragen symboliseert een nieuw begin.',
      kny_zodiac_h: '<span class="icon" aria-hidden="true">\ud83d\udc34</span> Khmer-dierenriem',
      kny_zodiac_p: 'De Khmer-dierenriem volgt een 12-jarige dierencyclus. 2026 is het <strong>Jaar van het Paard</strong> (\u1786\u17d2\u1793\u17b6\u17c6\u1798\u1798\u17b8).',
      kny_zodiac_fact_label: '2026 \u2014 Jaar van het Paard \u00b7 \u1786\u17d2\u1793\u17b6\u17c6\u1798\u1798\u17b8',
      kny_zodiac_fact_p: 'Het Paard symboliseert energie, vrijheid en avontuur.',
      kny_zodiac_col_animal: 'Dier',
      kny_zodiac_col_khmer: 'Khmer',
      kny_zodiac_col_years: 'Jaren',
      kny_greetings_h: '<span class="icon" aria-hidden="true">\ud83d\ude4f</span> Nieuwjaarswensen',
      kny_greetings_p: 'Zeg "Gelukkig Nieuwjaar" in de vieringen:',
      kny_footer: '\u00a9 2026 ShyTalk \u00b7 Choul Chnam Thmey vieren',
    },
