      kny_trad3_h: 'Mont\u00edculos de areia (\u1797\u17d2\u1793\u17c6\u1781\u17d2\u179f\u17b6\u1785\u17cb)', kny_trad3_p: 'Pequenas montanhas de areia s\u00e3o constru\u00eddas nos templos.',
      kny_trad4_h: 'Jogos tradicionais', kny_trad4_p: '<strong>Chol Chhoung</strong>, <strong>Leak Kanseng</strong> e cabo de guerra unem as comunidades.',
