      kny_what_p1: '<strong>Choul Chnam Thmey</strong> (\u1786\u17bc\u179b\u1786\u17d2\u1793\u17b6\u17c6\u1790\u17d2\u1798\u17b8) \u043e\u0437\u043d\u0430\u0447\u0430\u0435\u0442 \u00ab\u0432\u0445\u043e\u0434 \u0432 \u043d\u043e\u0432\u044b\u0439 \u0433\u043e\u0434\u00bb \u0438 \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0441\u0430\u043c\u044b\u043c \u043f\u0440\u0430\u0437\u0434\u043d\u0443\u0435\u043c\u044b\u043c \u043f\u0440\u0430\u0437\u0434\u043d\u0438\u043a\u043e\u043c \u041a\u0430\u043c\u0431\u043e\u0434\u0436\u0438. \u041e\u0442\u043c\u0435\u0447\u0430\u0435\u0442\u0441\u044f \u0441 <strong>13 \u043f\u043e 16 \u0430\u043f\u0440\u0435\u043b\u044f</strong>.',
      kny_what_p2: '\u0423\u0445\u043e\u0434\u044f\u0449\u0438\u0439 \u043a\u043e\u0440\u043d\u044f\u043c\u0438 \u0432 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u044e \u0431\u0443\u0434\u0434\u0438\u0437\u043c\u0430 \u0442\u0445\u0435\u0440\u0430\u0432\u0430\u0434\u044b, \u043f\u0440\u0430\u0437\u0434\u043d\u0438\u043a \u2014 \u044d\u0442\u043e \u0432\u0440\u0435\u043c\u044f \u0434\u0443\u0445\u043e\u0432\u043d\u043e\u0433\u043e \u043e\u0431\u043d\u043e\u0432\u043b\u0435\u043d\u0438\u044f \u0438 \u0441\u0435\u043c\u0435\u0439\u043d\u043e\u0433\u043e \u0441\u0431\u043e\u0440\u0430.',
      kny_what_p3: '\u041f\u0440\u0430\u0437\u0434\u043d\u043e\u0432\u0430\u043d\u0438\u0435 \u0441\u043e\u0432\u043f\u0430\u0434\u0430\u0435\u0442 \u0441 \u043a\u043e\u043d\u0446\u043e\u043c \u0437\u0430\u0441\u0443\u0448\u043b\u0438\u0432\u043e\u0433\u043e \u0441\u0435\u0437\u043e\u043d\u0430. \u041a\u0443\u043b\u044c\u0442\u0443\u0440\u043d\u044b\u0435 \u0441\u0432\u044f\u0437\u0438 \u0441 <strong>Songkran</strong> \u0432 \u0422\u0430\u0438\u043b\u0430\u043d\u0434\u0435, <strong>Pi Mai</strong> \u0432 \u041b\u0430\u043e\u0441\u0435 \u0438 <strong>Thingyan</strong> \u0432 \u041c\u044c\u044f\u043d\u043c\u0435.',
      kny_days_h: '<span class="icon" aria-hidden="true">\ud83d\udcff</span> \u0422\u0440\u0438 \u0434\u043d\u044f',
      kny_days_intro: '\u0427\u043e\u043b \u0427\u043d\u0430\u043c \u0422\u0445\u043c\u044d\u0439 \u043f\u0440\u043e\u0445\u043e\u0434\u0438\u0442 \u0432 \u0442\u0435\u0447\u0435\u043d\u0438\u0435 \u0442\u0440\u0451\u0445 \u0446\u0435\u0440\u0435\u043c\u043e\u043d\u0438\u0430\u043b\u044c\u043d\u044b\u0445 \u0434\u043d\u0435\u0439.',
      kny_day1_label: 'Maha Sangkran \u2014 \u1798\u17a0\u17b6\u179f\u1784\u17d2\u1780\u17d2\u179a\u17b6\u1793\u17d2\u178f',
      kny_day1_date: '\u0414\u0435\u043d\u044c 1 \u00b7 13 \u0430\u043f\u0440\u0435\u043b\u044f',
      kny_day1_p: '\u041f\u0435\u0440\u0432\u044b\u0439 \u0434\u0435\u043d\u044c \u043e\u0437\u043d\u0430\u0447\u0430\u0435\u0442 \u043f\u0440\u0438\u0431\u044b\u0442\u0438\u0435 \u043d\u043e\u0432\u043e\u0433\u043e \u0430\u043d\u0433\u0435\u043b\u0430 (<strong>Tevoda</strong>). \u0421\u0435\u043c\u044c\u0438 \u0443\u0431\u0438\u0440\u0430\u044e\u0442 \u0434\u043e\u043c\u0430 \u0438 \u043d\u0430\u0434\u0435\u0432\u0430\u044e\u0442 \u043d\u043e\u0432\u0443\u044e \u043e\u0434\u0435\u0436\u0434\u0443.',
