      kny_day3_label: 'Tngai Leang Sak \u2014 \u1790\u17d2\u1784\u17c3\u179b\u17be\u1784\u179f\u1780',
      kny_day3_date: '\u0414\u0435\u043d\u044c 3 \u00b7 15\u201316 \u0430\u043f\u0440\u0435\u043b\u044f',
      kny_day3_p: '\u041f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0439 \u0434\u0435\u043d\u044c \u2014 \u0441\u0430\u043c\u044b\u0439 \u0441\u0432\u044f\u0449\u0435\u043d\u043d\u044b\u0439. \u0411\u0443\u0434\u0434\u0438\u0441\u0442\u044b \u043e\u043c\u044b\u0432\u0430\u044e\u0442 <strong>\u0441\u0442\u0430\u0442\u0443\u0438 \u0411\u0443\u0434\u0434\u044b</strong> \u0430\u0440\u043e\u043c\u0430\u0442\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u043e\u0439 \u0432\u043e\u0434\u043e\u0439.',
      kny_traditions_h: '<span class="icon" aria-hidden="true">\u2728</span> \u0422\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u0438 \u043e\u0431\u044b\u0447\u0430\u0438',
      kny_trad1_h: '\u041f\u043e\u0441\u0435\u0449\u0435\u043d\u0438\u0435 \u0445\u0440\u0430\u043c\u043e\u0432', kny_trad1_p: '\u0412\u0435\u0440\u0443\u044e\u0449\u0438\u0435 \u043f\u0440\u0438\u043d\u043e\u0441\u044f\u0442 \u0435\u0434\u0443, \u0446\u0432\u0435\u0442\u044b \u0438 \u0431\u043b\u0430\u0433\u043e\u0432\u043e\u043d\u0438\u044f.',
      kny_trad2_h: '\u0412\u043e\u0434\u043d\u044b\u0435 \u0446\u0435\u0440\u0435\u043c\u043e\u043d\u0438\u0438', kny_trad2_p: '\u0410\u0440\u043e\u043c\u0430\u0442\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u0443\u044e \u0432\u043e\u0434\u0443 \u043b\u044c\u044e\u0442 \u043d\u0430 \u0440\u0443\u043a\u0438 \u0441\u0442\u0430\u0440\u0448\u0438\u0445.',
      kny_trad3_h: '\u041f\u0435\u0441\u0447\u0430\u043d\u044b\u0435 \u0445\u043e\u043b\u043c\u0438\u043a\u0438 (\u1797\u17d2\u1793\u17c6\u1781\u17d2\u179f\u17b6\u1785\u17cb)', kny_trad3_p: '\u041c\u0430\u043b\u0435\u043d\u044c\u043a\u0438\u0435 \u043f\u0435\u0441\u0447\u0430\u043d\u044b\u0435 \u0433\u043e\u0440\u043a\u0438 \u0441\u0442\u0440\u043e\u044f\u0442\u0441\u044f \u0432 \u0445\u0440\u0430\u043c\u0430\u0445.',
