      kny_trad5_h: '\u041a\u0445\u043c\u0435\u0440\u0441\u043a\u0430\u044f \u043a\u0443\u0445\u043d\u044f', kny_trad5_p: '<strong>Num Ansom</strong>, <strong>Kralan</strong> \u0438 \u0440\u0430\u0437\u043b\u0438\u0447\u043d\u044b\u0435 \u043a\u0430\u0440\u0440\u0438 \u0433\u043e\u0442\u043e\u0432\u044f\u0442\u0441\u044f \u0437\u0430\u0440\u0430\u043d\u0435\u0435.',
      kny_trad6_h: '\u041d\u043e\u0432\u0430\u044f \u043e\u0434\u0435\u0436\u0434\u0430 \u0438 \u0441\u0435\u043c\u044c\u044f', kny_trad6_p: '\u041d\u043e\u0441\u0438\u0442\u044c \u043d\u043e\u0432\u0443\u044e \u043e\u0434\u0435\u0436\u0434\u0443 \u0441\u0438\u043c\u0432\u043e\u043b\u0438\u0437\u0438\u0440\u0443\u0435\u0442 \u043d\u043e\u0432\u043e\u0435 \u043d\u0430\u0447\u0430\u043b\u043e.',
      kny_zodiac_h: '<span class="icon" aria-hidden="true">\ud83d\udc34</span> \u041a\u0445\u043c\u0435\u0440\u0441\u043a\u0438\u0439 \u0437\u043e\u0434\u0438\u0430\u043a',
      kny_zodiac_p: '\u041a\u0445\u043c\u0435\u0440\u0441\u043a\u0438\u0439 \u0437\u043e\u0434\u0438\u0430\u043a \u0441\u043b\u0435\u0434\u0443\u0435\u0442 12-\u043b\u0435\u0442\u043d\u0435\u043c\u0443 \u0446\u0438\u043a\u043b\u0443. 2026 \u2014 <strong>\u0413\u043e\u0434 \u041b\u043e\u0448\u0430\u0434\u0438</strong> (\u1786\u17d2\u1793\u17b6\u17c6\u1798\u1798\u17b8).',
