      kny_trad4_h: 'Traditionella spel', kny_trad4_p: '<strong>Chol Chhoung</strong>, <strong>Leak Kanseng</strong> och dragkamp f\u00f6renar samh\u00e4llen.',
      kny_trad5_h: 'Khmer-mat', kny_trad5_p: '<strong>Num Ansom</strong>, <strong>Kralan</strong> och curry f\u00f6rbereds dagarna innan.',
      kny_trad6_h: 'Nya kl\u00e4der och familj', kny_trad6_p: 'Att b\u00e4ra nya kl\u00e4der symboliserar en nystart.',
      kny_zodiac_h: '<span class="icon" aria-hidden="true">\ud83d\udc34</span> Khmer-djurkretsen',
      kny_zodiac_p: 'Khmer-djurkretsen f\u00f6ljer en 12-\u00e5rig djurcykel. 2026 \u00e4r <strong>H\u00e4stens \u00e5r</strong> (\u1786\u17d2\u1793\u17b6\u17c6\u1798\u1798\u17b8).',
      kny_zodiac_fact_label: '2026 \u2014 H\u00e4stens \u00e5r \u00b7 \u1786\u17d2\u1793\u17b6\u17c6\u1798\u1798\u17b8',
